        @mcp.tool()
        async def pdf_find_and_replace_text(
            input_filename: str,
            find_text: str,
            replace_text: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Find and replace text in a PDF document.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre-placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename (str): Bare filename of the PDF to modify.
                find_text (str): Text to search for.
                replace_text (str): Text to replace the found occurrences with.
                output_filename (str | None, optional): Bare filename for the updated PDF; if omitted, the original file is overwritten.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If the input PDF does not exist.
                Exception: Any unexpected error raised by Aspose.PDF.
        
            Example:
                result = await pdf_find_and_replace_text(
                    input_filename="report.pdf",
                    find_text="Draft",
                    replace_text="Final",
                    output_filename="report_final.pdf"
                )
            """
            # Resolve and validate input file
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # sanitize and resolve output filename
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # overwrite original file
                output_filename = input_filename
                resolved_output = str(temp_output_path("aspose_pdf_result", ".pdf"))
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # Import Aspose.PDF (lazy import as required)
            import aspose.pdf as ap
        
            try:
                # Load document
                doc = ap.Document(str(resolved_input))
        
                # Find text fragments
                absorber = ap.text.TextFragmentAbsorber(find_text)
                doc.pages.accept(absorber)
        
                # Replace text in each fragment
                for fragment in absorber.text_fragments:
                    fragment.text = replace_text
        
                # Save the updated document
                doc.save(str(resolved_output))
        
                logger.info(
                    "Replaced text in PDF '%s' (search: '%s', replace: '%s') -> '%s'",
                    input_filename,
                    find_text,
                    replace_text,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": f"Text replacement completed. Output file: {output_filename}",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error during PDF find/replace")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}

