        @mcp.tool()
        async def pdf_delete_page(
            input_filename: str,
            page_number: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Delete a specific page from a PDF document.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the PDF to modify, e.g. "report.pdf".
                page_number: 1‑based index of the page to delete.
                output_filename: optional bare filename for the resulting PDF. If omitted, the original file is overwritten.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: if the input file does not exist.
                ValueError: if page_number is out of range.
        
            Example:
                result = await pdf_delete_page("report.pdf", 2, "report_trimmed.pdf")
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename (strip nulls, keep only name)
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output location
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
                # ensure the directory exists
                Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
                final_output_name = output_filename
            else:
                # overwrite original file – use a temporary path then replace
                temp_path = temp_output_path("aspose_pdf_result", ".pdf")
                resolved_output = str(temp_path)  # Aspose expects a plain string
                final_output_name = input_filename
        
            # ----------------------------------------------------------------------
            # Perform PDF page deletion using Aspose
            # ----------------------------------------------------------------------
            try:
                import aspose.pdf as ap
        
                doc = ap.Document(str(resolved_input))
        
                total_pages = len(doc.pages)
                if page_number < 1 or page_number > total_pages:
                    raise ValueError(
                        f"page_number {page_number} is out of range (1‑{total_pages})"
                    )
        
                doc.pages.delete(page_number)
                doc.save(str(resolved_output))
        
                # If we wrote to a temporary file for overwrite, replace the original
                if output_filename is None:
                    Path(resolved_input).unlink(missing_ok=True)
                    Path(resolved_output).replace(resolved_input)
        
                return {
                    "status": "success",
                    "message": f"Page {page_number} deleted successfully.",
                    "output_filename": final_output_name,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to delete PDF page")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": final_output_name if "final_output_name" in locals() else "",
                }

        @mcp.tool()
        async def pdf_rotate_page(
            input_filename: str,
            page_number: int,
            degrees: int,
            output_filename: str | None = None,
        ) -> dict:
            """Rotate a specific page in a PDF.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the source PDF, e.g. 'report.pdf'.
                page_number: 1‑based index of the page to rotate.
                degrees: rotation angle; must be one of 90, 180, 270.
                output_filename: optional bare filename for the rotated PDF. If omitted, a temporary file is created.
        
            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str}
        
            Raises:
                FileNotFoundError: if the input file does not exist.
                ValueError: for invalid degrees or page number.
        
            Example:
                result = await pdf_rotate_page("report.pdf", 2, 90, "report_rotated.pdf")
            """
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # ---- Resolve input file -------------------------------------------------
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---- Validate rotation angle --------------------------------------------
            if degrees not in (90, 180, 270):
                return {
                    "status": "error",
                    "message": f"Invalid rotation angle: {degrees}. Allowed values are 90, 180, 270.",
                    "output_filename": "",
                }
        
            # ---- Resolve output file -------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                resolved_output = str(temp_output_path("aspose_pdf_result", ".pdf"))
                output_filename = Path(resolved_output).name
        
            # Ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ---- Perform rotation using Aspose ---------------------------------------
            try:
                import aspose.pdf as ap
        
                doc = ap.Document(str(resolved_input))
        
                # Validate page number
                if page_number < 1 or page_number > len(doc.pages):
                    return {
                        "status": "error",
                        "message": f"Page number {page_number} is out of range. Document has {len(doc.pages)} pages.",
                        "output_filename": output_filename,
                    }
        
                rotation_map = {90: ap.Rotation.ON90, 180: ap.Rotation.ON180, 270: ap.Rotation.ON270}
                doc.pages[page_number].rotate = rotation_map[degrees]
        
                doc.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": "Page rotated successfully.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error rotating PDF page")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

