        @mcp.tool()
        async def pdf_split_to_pages(
            input_filename: str,
            output_filename_prefix: str | None = None,
        ) -> dict:
            """
            Split a PDF into separate one‑page PDF files.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'report.pdf') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output files are also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the PDF to split, e.g. 'report.pdf'.
                output_filename_prefix: optional prefix for generated page files; defaults to "page_".
                    The prefix is used as‑is (e.g. "chapter_" → "chapter_1.pdf", "chapter_2.pdf", …).
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the first generated page file
                }
        
            Raises:
                FileNotFoundError: if the input PDF does not exist in ASPOSE_FILES_PATH.
                Exception: any unexpected error from Aspose.PDF.
        
            Example:
                >>> result = await pdf_split_to_pages("report.pdf", "page_")
                >>> result["status"]
                'success'
                >>> result["output_filename"]
                'page_1.pdf'
            """
            # ---------- Resolve and validate input ----------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename (remove null bytes, keep only the name)
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # sanitize / set default prefix
            if output_filename_prefix is None:
                output_filename_prefix = "page_"
            else:
                output_filename_prefix = output_filename_prefix.strip().replace("\x00", "")
        
            # ---------- Aspose.PDF processing ----------
            try:
                import aspose.pdf as ap
        
                doc = ap.Document(str(resolved_input))
                page_count = len(doc.pages)
        
                for i in range(1, page_count + 1):  # 1‑based indexing
                    new_doc = ap.Document()
                    new_doc.pages.add(doc.pages[i])
                    output_name = f"{output_filename_prefix}{i}.pdf"
                    resolved_output = get_safe_path(output_name)
                    # ensure the target directory exists
                    Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
                    new_doc.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": f"PDF split into {page_count} pages.",
                    "output_filename": f"{output_filename_prefix}1.pdf",
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error splitting PDF '%s': %s", input_filename, exc)
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def pdf_extract_pages(
            input_filename: str,
            start_page: int,
            end_page: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Extract a range of pages from an existing PDF file.
        
            IMPORTANT:
                * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
                * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
                * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
                * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the source PDF, e.g. 'report.pdf' — must already exist in ASPOSE_FILES_PATH.
                start_page: 1‑based index of the first page to extract.
                end_page: 1‑based index of the last page to extract (inclusive).
                output_filename: optional bare filename for the extracted PDF. If omitted, 'extracted.pdf' is used.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (only on success)
                }
        
            Raises:
                FileNotFoundError: if the input file does not exist.
                ValueError: if page numbers are invalid (out of range or start > end).
        
            Example:
                result = await pdf_extract_pages(
                    input_filename="report.pdf",
                    start_page=2,
                    end_page=5,
                    output_filename="summary.pdf"
                )
            """
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # ---- Resolve and validate input file ----
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---- Resolve output file ----
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                output_filename = "extracted.pdf"
                resolved_output = str(temp_output_path("aspose_pdf_result", ".pdf"))
            # Ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            try:
                # ---- Validate page range ----
                import aspose.pdf as ap
        
                doc = ap.Document(str(resolved_input))
                total_pages = len(doc.pages)
                if start_page < 1 or end_page < 1:
                    raise ValueError("Page numbers must be 1 or greater.")
                if start_page > end_page:
                    raise ValueError("start_page cannot be greater than end_page.")
                if end_page > total_pages:
                    raise ValueError(
                        f"end_page ({end_page}) exceeds total pages ({total_pages}) in the document."
                    )
        
                # ---- Perform extraction ----
                import aspose.pdf.facades as facades
        
                editor = facades.PdfFileEditor()
                editor.extract(str(resolved_input), start_page, end_page, str(resolved_output))
        
                logger.info(
                    "Extracted pages %d‑%d from %s to %s",
                    start_page,
                    end_page,
                    input_filename,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": f"Pages {start_page}-{end_page} extracted successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.error("Failed to extract pages: %s", exc)
                return {"status": "error", "message": str(exc)}

