        async def pdf_add_text_stamp(
            input_filename: str,
            text: str,
            opacity: float | None = None,
            output_filename: str | None = None,
        ) -> dict:
            """
            Add a background text watermark to every page of a PDF.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'report.pdf') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the PDF to watermark, e.g. 'report.pdf'.
                text: Watermark text to place on each page.
                opacity: Optional transparency between 0.0 (fully transparent) and 1.0 (opaque). Defaults to 1.0 if omitted.
                output_filename: Optional bare filename for the watermarked PDF. If omitted, the original file is overwritten.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If the input PDF does not exist.
                ValueError: If opacity is provided but not in the range [0.0, 1.0].
        
            Example:
                result = await pdf_add_text_stamp(
                    input_filename="contract.pdf",
                    text="CONFIDENTIAL",
                    opacity=0.3,
                    output_filename="contract_watermarked.pdf"
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output file
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
                final_output_name = output_filename
            else:
                # overwrite original file – use the same bare name
                resolved_output = get_safe_path(input_filename)
                final_output_name = input_filename
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Validate opacity
            # ----------------------------------------------------------------------
            if opacity is not None:
                if not (0.0 <= opacity <= 1.0):
                    raise ValueError("opacity must be between 0.0 and 1.0")
        
            # ----------------------------------------------------------------------
            # Aspose PDF processing
            # ----------------------------------------------------------------------
            try:
                import aspose.pdf as ap
        
                doc = ap.Document(str(resolved_input))
                stamp = ap.TextStamp(text)
                stamp.background = True
                if opacity is not None:
                    stamp.opacity = opacity
                else:
                    stamp.opacity = 1.0
        
                for page in doc.pages:
                    page.add_stamp(stamp)
        
                doc.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": f"Text stamp applied to '{input_filename}'.",
                    "output_filename": final_output_name,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to add text stamp")
                return {"status": "error", "message": str(exc)}

