        @mcp.tool()
        async def pdf_encrypt(
            input_filename: str,
            user_password: str,
            owner_password: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Encrypt a PDF file with user and owner passwords.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the PDF to encrypt, e.g. 'report.pdf'.
                user_password: password required to open the encrypted PDF.
                owner_password: password that grants full permissions on the encrypted PDF.
                output_filename: optional bare filename for the encrypted PDF; if omitted, the original file is overwritten.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: if the input file does not exist.
                Exception: any unexpected error from Aspose.Pdf.
        
            Example:
                result = await pdf_encrypt(
                    input_filename="draft.pdf",
                    user_password="user123",
                    owner_password="owner456",
                    output_filename="draft_encrypted.pdf"
                )
            """
            # ---------- Resolve and validate input ----------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize and resolve input file
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---------- Resolve output ----------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                # overwrite original file
                output_filename = input_filename
                resolved_output = get_safe_path(output_filename)
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ---------- Aspose PDF encryption ----------
            try:
                import aspose.pdf.facades as facades
        
                security = facades.PdfFileSecurity()
                security.bind_pdf(str(resolved_input))
                security.encrypt_file(
                    user_password,
                    owner_password,
                    facades.DocumentPrivilege.allow_all,
                    facades.KeySize.X128,
                )
                security.save(str(resolved_output))
        
                logger.info(
                    "Encrypted PDF '%s' -> '%s'",
                    input_filename,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": "PDF encrypted successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to encrypt PDF '%s': %s", input_filename, exc)
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

